// Validate webhook payload from Google Apps Script
const input = $input.first().json;

// Verify source
if (input.source !== 'google_apps_script') {
  throw new Error('Invalid source: ' + input.source);
}

// Extract event data
const event = input.event || {};

return [{
  json: {
    calendar_id: input.calendar_id,
    event_id: event.id,
    event_title: event.title,
    event_start: event.start,
    event_end: event.end,
    event_status: event.status,
    event_description: event.description,
    last_updated: event.lastUpdated,
    html_link: event.htmlLink,
    sync_type: input.sync_type,
    received_at: new Date().toISOString()
  }
}];

// No matching booking found - this is an orphan event
// Log it for manual review
const event = $('Validate Webhook').first().json;

return [{
  json: {
    action: 'orphan_event_detected',
    event_id: event.event_id,
    event_title: event.event_title,
    event_start: event.event_start,
    message: 'Event exists in GCal but not in DB - may need manual review',
    requires_action: true
  }
}];

// Standard Contract Output
const input = $input.first().json;
const webhookData = $('Validate Webhook').first().json;

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      synced: true,
      calendar_id: webhookData.calendar_id,
      event_id: webhookData.event_id,
      action_taken: input.action || 'sync_completed',
      booking_id: input.booking_id || null,
      requires_manual_review: input.requires_action || false
    },
    _meta: {
      source: 'WF4_SYNC_ENGINE_EVENT_DRIVEN',
      timestamp: new Date().toISOString(),
      version: '2.0.0'
    }
  }
}];

// Handle cancelled event result
const cancelled = $input.first().json;

return [{
  json: {
    action: 'booking_cancelled',
    booking_id: cancelled.booking_id,
    status: cancelled.status,
    customer_id: cancelled.customer_id,
    message: 'Booking cancelled due to GCal event deletion'
  }
}];
